mapper.select:
SELECT
	SUM(r.deal_number) AS sellNumber,
	SUM(
		(
			IFNULL(c2.transport_amount, 0)
		) * r.deal_number / c1.total_number + (
			IFNULL(c1.transport_amount, 0)
		)
	) AS transportAmount,
	SUM(
		(
			r.sell_price - r.buy_price
		) * r.deal_number
	) AS balance,
	SUM(
		(
			(
				r.sell_price - r.buy_price
			) * r.deal_number
		) - (
			IFNULL(c2.transport_amount, 0)
		 * r.deal_number / c1.total_number + 
			IFNULL(c1.transport_amount, 0)
		)
	) AS profit,
	SUM(
		(
			(
				r.sell_price - r.buy_price
			) * r.deal_number
		) - (
			IFNULL(c2.transport_amount, 0)
		 * r.deal_number / c1.total_number + 
			IFNULL(c1.transport_amount, 0)
		)
	) * 0.4 AS bountyAmoun,
	SUM(
		(
			(
				r.sell_price - r.buy_price
			) * r.deal_number
		) - (
			IFNULL(c2.transport_amount, 0)
		 * r.deal_number / c1.total_number + 
			IFNULL(c1.transport_amount, 0)
		)
	) * 0.2 AS bounty
FROM
	t_ctr_contract c1
LEFT JOIN t_ctr_contract_rela r ON c1.id = r.sell_contract_id
LEFT JOIN t_ctr_contract c2 ON c2.id = r.buy_contract_id
WHERE
	c1.source = 'MS'
AND c1.pay_full_time != ''
AND c2.source = 'MB'
AND c1.pay_full_time = c2.pay_full_time
AND c1.enterprise_id = #{enterpriseId}
